const aiResponse = $input.item.json.choices[0].message.content;
const parsed = JSON.parse(aiResponse.replace(/```json|```/g, '').trim());

return {
  json: {
    searchParams: {
      location: parsed.location || '',
      dateStart: parsed.dateRange?.start || '',
      dateEnd: parsed.dateRange?.end || '',
      tripType: parsed.tripType || 'all',
      keywords: parsed.keywords || [],
      originalQuery: $input.item.json.originalQuery
    },
    userId: $input.item.json.userId,
    conversationId: $input.item.json.conversationId
  }
};

const gmailData = $input.item.json.gmailResults || [];
const calendarData = $input.item.json.calendarResults || [];
const photosData = $input.item.json.photosResults || [];
const searchParams = $input.item.json.searchParams;

// Combine and deduplicate data
const allResults = [
  ...gmailData.map(item => ({ source: 'gmail', type: 'booking', ...item })),
  ...calendarData.map(item => ({ source: 'calendar', type: 'event', ...item })),
  ...photosData.map(item => ({ source: 'photos', type: 'image', ...item }))
];

// Filter by relevance
const filtered = allResults.filter(item => {
  const itemText = JSON.stringify(item).toLowerCase();
  const location = searchParams.location.toLowerCase();
  return itemText.includes(location);
});

return {
  json: {
    results: filtered,
    totalFound: filtered.length,
    searchParams: searchParams,
    sources: {
      gmail: gmailData.length,
      calendar: calendarData.length,
      photos: photosData.length
    }
  }
};

