const aiResponse = $input.item.json.content[0].text;
const results = $input.item.json.results || [];
const searchParams = $input.item.json.searchParams;

// Format final response
const response = {
  success: true,
  conversationId: $input.item.json.conversationId,
  query: searchParams.originalQuery,
  answer: aiResponse,
  metadata: {
    totalResults: results.length,
    sources: $input.item.json.sources,
    searchParams: searchParams
  },
  results: results.slice(0, 10).map(r => ({
    title: r.title || r.summary || 'Trip Memory',
    date: r.date || r.startTime,
    location: r.location || searchParams.location,
    type: r.type,
    source: r.source,
    imageUrl: r.imageUrl || null,
    details: r.details || {}
  })),
  suggestions: [
    `Show more trips to ${searchParams.location}`,
    `Find photos from this trip`,
    `See all ${searchParams.tripType} bookings`
  ]
};

return { json: response };
